voorlezeneerst = false;

function orgineletekst() {

  overlayObject.show();

  clearcontent();



  settopbuttons("orgineletekst");
  settoptitel("orgineletekst");

  overlayObject.hide();

  tekstpagecounter++;

  orginelebericht = nn_data.find((x) => x.Id == lastid).orginele_bericht;
  orgineletekststing = filterFlashTekst(orginelebericht);
  orgineletekststing = orgineletekststing.replace(/\s(?=\s)/g, "&nbsp;");
  orgineletekststing = orgineletekststing.replace(/&nbsp; /g, "&nbsp;&nbsp;");


  

  readpeakerbutton =
    '<div id="readSpeakerStarten" class="rs_skip" onclick="readThisVoorleesText({id:' +
        lastid +', type: \'org\', template: 1});"><div id="readspekervoorlezen" class="geleKnop" style="padding:2px; padding-left:5px; padding-right:5px; font-size: 0.8em;"><img src="img/voorlezen.png" style="width:18px; height: 18px;"/></div></div> <div style="padding:2px; padding-left:5px; padding-right:5px; font-size: 0.8em; display: none;" onclick="stopReading()" class="geleKnop" id="readSpeakerStoppen">stoppen</div>';

  $("#stageholder").remove();
  $("#stage").empty();
  $("#stage").append("<div id='stageholder'></div>");
  $("#stageholder").append(
    "<div id='holderout' style='overflow-y: auto; overflow-x: hidden; position: relative; width: 736px; height:410px; top: 50px; left:20px;'></div>"
  );
  $("#holderout").append(
    "<div id='holdertable' style='display: table; width:100%; min-height: 100%;'></div>"
  );
  $("#holdertable").append(
    "<div id='holdercell' style='display: table-cell; text-align: center; vertical-align: middle;'></div>"
  );

  $("#stageholder").append(
    "<div style='position:absolute; top:5px; right:5px;display:block;' id='readspekerholderbuttons'><div style='display:inline-block'>" +
      readpeakerbutton +
      "</div></div>"
  );

  $("#holdercell").append(
    "<div class='readThisText replaceThisLeesTekst' id='holdercontentorg" +
      tekstpagecounter +
      "' style='text-align: left; padding:10px; line-height: 1.15em; font-size:1em;'>" +
      orgineletekststing +
      "</div>"
  );
}

