function filterTekstOefening(tekst) {
  tekst = tekst.replace(/(\r\n|\n|\r)/gm, "");
  tekst = tekst.replace(/\[afbeelding\].+?\[\/afbeelding\]/g, "");
  tekst = tekst.replace(/\[br\]/g, "<br>");

  tekst = tekst.replace(/<br><br><br>/g, "<br><br>");
  tekst = tekst.replace(/<br><br><br>/g, "<br><br>");
  tekst = tekst.replace(/<br><br><br>/g, "<br><br>");
  tekst = tekst.replace(/<br><br><br>/g, "<br><br>");
  tekst = tekst.replace(/<br><br><br>/g, "<br><br>");
  tekst = tekst.replace(/<br><br><br>/g, "<br><br>");

  return tekst;
}

