function OTgalgje_find() {
  if (!OTgalgje_klaar) {
    $("#" + OTgalgje_currentId).unbind(clickevent);
    $("#" + OTgalgje_currentId).attr("clickedthis", "1");

    temp_array = OTgalgje_woord_zichtbaar.split("");
    temp_array2 = OTgalgje_woord.split("");
    found = false;
    OTgalgje_woord_zichtbaar = "";
    for (a = 0; a < temp_array.length; a++) {
      if (temp_array[a] == "_") {
        temp = temp_array2[a];
        temp = temp.toLowerCase();
        if (temp == "ë") {
          temp = "e";
        }
        if (temp == "ä") {
          temp = "a";
        }
        if (temp == "ü") {
          temp = "u";
        }
        if (temp == "ï") {
          temp = "i";
        }
        if (temp == "ö") {
          temp = "o";
        }
        if (temp == "ç") {
          temp = "c";
        }
        if (temp == "é") {
          temp = "e";
        }
        if (temp == "á") {
          temp = "a";
        }
        if (temp == "ú") {
          temp = "u";
        }
        if (temp == "í") {
          temp = "i";
        }
        if (temp == "ó") {
          temp = "o";
        }
        if (temp == "è") {
          temp = "e";
        }
        if (temp == "à") {
          temp = "a";
        }
        if (temp == "ù") {
          temp = "u";
        }
        if (temp == "ì") {
          temp = "i";
        }
        if (temp == "ò") {
          temp = "o";
        }

        if ($("#" + OTgalgje_currentId).attr("letter") == temp) {
          found = true;
          OTgalgje_woord_zichtbaar = OTgalgje_woord_zichtbaar + temp_array2[a];
        } else {
          OTgalgje_woord_zichtbaar = OTgalgje_woord_zichtbaar + "_";
        }
      } else {
        OTgalgje_woord_zichtbaar = OTgalgje_woord_zichtbaar + temp_array[a];
      }
    }
    if (found) {
      $("#" + OTgalgje_currentId).css({
        backgroundColor: "#009900",
        borderColor: "#009900",
        color: "#fff",
      });
      alles_found = true;
      temp_array = OTgalgje_woord_zichtbaar.split("");
      for (a = 0; a < temp_array.length; a++) {
        if (temp_array[a] == "_") {
          alles_found = false;
        }
      }
      if (alles_found) {

        OTgalgje_score = 100;
        score_OTgalgje();
        OTgalgje_klaar = true;
        $("#OTgalgje_letters").css({ opacity: 0.25 });
        $("#OTgalgje_woord").css({
          backgroundColor: "#009900",
          borderColor: "#009900",
          color: "#fff",
        });
      }
    } else {
      OTgalgje_beurt++;

      $("#OTgalgje_galg").css(
        "background-image",
        "url(img/galgje_" + (OTgalgje_beurt + 1) + ".png)"
      );

      if (OTgalgje_beurt == 6) {

        OTgalgje_klaar = true;
        OTgalgje_score = 0;
        score_OTgalgje();
        $("#OTgalgje_letters").css({ opacity: 0.25 });
        $("#OTgalgje_woord").css({
          backgroundColor: "#cc0000",
          borderColor: "#cc0000",
          color: "#fff",
        });
      }
      $("#" + OTgalgje_currentId).css({
        backgroundColor: "#cc0000",
        borderColor: "#cc0000",
        color: "#fff",
      });
    }

    $("#OTgalgje_woord").text(OTgalgje_woord_zichtbaar);
    if (OTgalgje_klaar) {
      $("#OTgalgje_woord").text(OTgalgje_woord);
    }
  }
}

