function loadTekstPage(id, niveau) {
  clearcontent();

  cleartoptitel();
  $("#titletekst").html("- " + vertaling["fv_knop_tekst_leestekst"]);
  $("#titletekst").playreadspeaker("leestekst");


  reload = false;


  nieuwsstartreaderdata = nn_data.filter(function (item) {
    return item.Id == id;
  })[0];

  nieuwsstartreaderdata.orgineleberichtvisible =
    nieuwsstartreaderdata.orginele_bericht_visible;
  nieuwsstartreaderdata.ntip = nieuwsstartreaderdata.leeshulp;
  if (niveau == "I") {
    nieuwsstartreaderdata.plaatstvoef = nieuwsstartreaderdata.oefening_place_1;
  }
  if (niveau == "II") {
    nieuwsstartreaderdata.plaatstvoef = nieuwsstartreaderdata.oefening_place_2;
  }
  nieuwsstartreaderdata.plaatstvoef2 = nieuwsstartreaderdata.oefening_place_2;

  let tellertemp = 0;
  for (let i = 0; i < nieuwsstartreaderdata.oefeningen.length; i++) {
    if (nieuwsstartreaderdata.oefeningen[i].niveau == niveau) {
      tellertemp++;
    }
  }

  nieuwsstartreaderdata.aantaloefeningen = tellertemp;
  lastid = id;
  lastniveau = niveau;

  createTekstPage();
}

function clearButtonBackground() {
  for (a = 1; a <= 15; a++) {
    $("#footerbutton" + a).css({ background: "" });
  }
}

function createTekstPage() {
  cleartoptitel();
  $("#titletekst").html("- " + vertaling["fv_knop_tekst_leestekst"]);
  $("#titletekst").playreadspeaker("leestekst");


  showpage("oefeningen");
  place = 0;
  aantal = Number(nieuwsstartreaderdata.aantaloefeningen);
  temp = 0;

  if (lastniveau == "I") {
    $("#footerbutton" + nieuwsstartreaderdata.plaatstvoef).show();
    $("#footerbutton" + nieuwsstartreaderdata.plaatstvoef).bind(
      clickevent,
      function () {
        placenowoefening = $(this).attr("id");

        stopReading();

        if (lasttypebookortekst == "boek") {
          overlayObject.show();
          setTimeout(function () {
            showleestekst();
          }, 100);
        } else {
          showleestekst();
        }
        $(this).css({ background: "#ff9900" });
      }
    );
    $(
      "#footerbutton" +
        nieuwsstartreaderdata.plaatstvoef +
        " .footerbuttontablecell"
    ).html(vertaling["fv_titel_leestekst"]);
    $("#footerbutton" + nieuwsstartreaderdata.plaatstvoef).playreadspeaker(
      "leestekst"
    );
  }
  if (lastniveau == "II") {
    $("#footerbutton" + nieuwsstartreaderdata.plaatstvoef2).show();
    $("#footerbutton" + nieuwsstartreaderdata.plaatstvoef2).bind(
      clickevent,
      function () {
        placenowoefening = $(this).attr("id");

        stopReading();
        if (lasttypebookortekst == "boek") {
          overlayObject.show();
          setTimeout(function () {
            showleestekst();
          }, 100);
        } else {
          showleestekst();
        }
        $(this).css({ background: "#ff9900" });
      }
    );
    $(
      "#footerbutton" +
        nieuwsstartreaderdata.plaatstvoef2 +
        " .footerbuttontablecell"
    ).html(vertaling["fv_titel_leestekst"]);
    $("#footerbutton" + nieuwsstartreaderdata.plaatstvoef).playreadspeaker(
      "leestekst"
    );
  }
  for (a = 1; a <= aantal; a++) {
    $("#footerbutton" + (a + place)).show();
    if (lastniveau == "I") {
      if (nieuwsstartreaderdata.plaatstvoef == a) {
        place++;
      }
    }
    if (lastniveau == "II") {
      if (nieuwsstartreaderdata.plaatstvoef2 == a) {
        place++;
      }
    }
    $("#footerbutton" + (a + place) + " .footerbuttontablecell").html(a);
    $("#footerbutton" + (a + place)).attr("oefid", a);
    $("#footerbutton" + (a + place)).bind(clickevent, function () {
      placenowoefening = $(this).attr("id");

      stopReading();
      showoefening($(this).attr("oefid"));
      $(this).css({ background: "#ff9900" });
    });
    $("#footerbutton" + (a + place)).show();
    $("#footerbutton" + (a + place)).playsound("oefening " + a + ".mp3");
  }

  $("#footerbutton" + (aantal + 3)).show();
  $("#footerbutton" + (aantal + 3) + " .footerbuttontablecell").html(
    vertaling["fv_titel_leestip"]
  );
  $("#footerbutton" + (aantal + 3)).bind(clickevent, function () {

    stopReading();

    clearButtonBackground();

    $(this).css({ background: "#ff9900" });
    showleestip();
  });
  $("#footerbutton" + (aantal + 3)).playsound("leestip.mp3");
  if (lasttypebookortekst != "boek") {
    if (nieuwsstartreaderdata.orgineleberichtvisible == "1") {
      $("#footerbutton" + (aantal + 4)).show();
      $("#footerbutton" + (aantal + 4) + " .footerbuttontablecell").html(
        vertaling["fv_titel_orginele_tekst"].replace(" ", "<br>")
      );
      $("#footerbutton" + (aantal + 4)).bind(clickevent, function () {

        stopReading();

        clearButtonBackground();

        $(this).css({ background: "#ff9900" });
        orgineletekst();
      });
      $("#footerbutton" + (aantal + 4)).playsound("originele bericht.mp3");
    }
  }
  loadleestekst(lastid);
}

