function loadleestekst(id) {
  jsonData = nn_data.filter(function (item) {
    return item.Id == id;
  })[0];

  jsonData.orgineleberichtvisible = jsonData.orginele_bericht_visible;
  jsonData.ntemplayen1 = jsonData.template_niveau_1;
  jsonData.ntemplayen2 = jsonData.template_niveau_2;
  jsonData.ntitel = jsonData.titel;
  jsonData.npic = jsonData.afbeelding;
  jsonData.nid = jsonData.id;
  jsonData.ntekst1 = jsonData.tekst_niveau_1;
  jsonData.ntekst2 = jsonData.tekst_niveau_2;
  jsonData.ndatum = jsonData.datum;
  jsonData.nplaats = jsonData.plaats;
  jsonData.ntip = jsonData.leeshulp;

  nieuwsreader = jsonData;
  nieuwsreader2 = jsonData;
  $("#" + placenowoefening).trigger(clickevent);

}

