function showHelpVideo(videoName) {
  $("#main").hide();

  $("body").append("<div id='videooverlay'></div>");

  $("#videooverlay").append(
    '<div class="videooverlayframe" style="border: 2px solid #000;  background: #000000;" width="640" height="480" ><video id="helpvideo" width="640" height="480" autoplay><source src="' +
      videoName +
      '" type="video/mp4">Your browser does not support the video tag.</video></div>'
  );

  $("#videooverlay").append(
    '<div id="closevideo" style="cursor:pointer; position: absolute; top:50%; left:50%; margin-top: -270px;  margin-left: 330px; width:20px; height:20px; line-height:20px; font-size:24px; text-align: center; font-weight: bold; color: #ffffff;">X</div>'
  );

  $("#helpvideo").get(0).play();
  $("#helpvideo").bind("ended", function () {
    document.querySelectorAll('video').forEach(vid => vid.pause());
	$("#videooverlay").remove();
    $("#main").show();
	
  });

  $("#videooverlay").bind(clickevent, function () {
    document.querySelectorAll('video').forEach(vid => vid.pause());
	$("#videooverlay").remove();
    $("#main").show();
  });

  $("#closevideo").bind(clickevent, function () {
    document.querySelectorAll('video').forEach(vid => vid.pause());
	$("#videooverlay").remove();
    $("#main").show();
  });
}

