function resize() {
  var viewportWidth = $(window).width();
  var viewportHeight = $(window).height();



  if (viewportWidth / viewportHeight < 4 / 3) {

    if (viewportWidth < 799 || viewportWidth > 801) {
      $("#viewport").attr("content", "width=800, user-scalable=no");
    }
  } else {

    if (viewportHeight < 599 || viewportHeight > 601) {
      viewportWidth = viewportWidth * (600 / viewportHeight);
      $("#viewport").attr(
        "content",
        "width=" + viewportWidth + ", user-scalable=no"
      );
    }
  }

  resizecount++;

  if (checkMobile()) {
  } else {
    availablewidth = $(window).width();
    availableheight = $(window).height();
    scale1 = availablewidth / 800;
    scale2 = availableheight / 600;
    if (scale1 > scale2) {
      scale1 = scale2;
    }
    $("#scene").css({ transform: "scale(" + scale1 + "," + scale1 + ")" });
  }
}

$(window).resize(function () {
  resize();
});

function checkMobile() {
  var deviceAgent = navigator.userAgent.toLowerCase();

  var isTouchDevice =
    Modernizr.touch ||
    deviceAgent.match(/(iphone|ipod|ipad)/) ||
    deviceAgent.match(/(android)/) ||
    deviceAgent.match(/(iemobile)/) ||
    deviceAgent.match(/iphone/i) ||
    deviceAgent.match(/ipad/i) ||
    deviceAgent.match(/ipod/i) ||
    deviceAgent.match(/blackberry/i) ||
    deviceAgent.match(/bada/i);

  if (isTouchDevice) {

    return true;
  } else {

    return false;
  }
}

