function playSound(soundfile) {
  if (checkMobile()) {
    sfile = "./sounds/" + soundfile;
    mp3 = new Audio(sfile);
    mp3.play();
  } else {
    timeoutsound = setTimeout(function () {
      sfile = "./sounds/" + soundfile;
      $("#Mp3Me").attr("src", sfile);
    }, 700);
  }
}
function stopSound() {
  if (checkMobile()) {
    mp3.pause();
  } else {
    clearTimeout(timeoutsound);
    $("#Mp3Me").attr("src", "");
  }
}

