function filterFlashTekst(temp) {
  temp = temp.replace(/\[is\]/g, "=");
  temp = temp.replace(
    /<FONT FACE\="Arial" SIZE\="11" COLOR\="#000000" LETTERSPACING\="0" KERNING\="0">/g,
    "\n"
  );
  temp = temp.replace(
    /<FONT FACE\="arial" SIZE\="11" COLOR\="#000000" LETTERSPACING\="0" KERNING\="0">/g,
    "\n"
  );
  temp = temp.replace(
    /<FONT FACE\="Arial" SIZE\="11" COLOR\="<br>000000" LETTERSPACING\="0" KERNING\="0">/g,
    "\n"
  );
  temp = temp.replace(
    /<FONT FACE\="arial" SIZE\="11" COLOR\="<br>000000" LETTERSPACING\="0" KERNING\="0">/g,
    "\n"
  );
  temp = temp.replace(/<<<and>>>/g, "&");
  temp = temp.replace(/<<<procent>>>/g, "%");
  temp = temp.replace(/<<<tilde>>>/g, "^");
  temp = temp.replace(/<\/FONT>/g, "");
  temp = temp.replace(/<TEXTFORMAT LEADING\="2"><P ALIGN\="LEFT">/g, "");
  temp = temp.replace(/<\/P><\/TEXTFORMAT>/g, "<br>");
  temp = temp.replace(/<space>/g, "\n");
  temp = temp.replace(/\+/g, " ");
  temp = temp.replace(/\[plus\]/g, "+");
  temp = temp.replace(/\[procent\]/g, "%");
  temp = temp.replace(/\[amp\]/g, "&amp;");
  temp = temp.replace(/\[apos\]/g, "'");
  temp = temp.replace(/\[quot\]/g, '"');
  temp = temp.replace(/\[dolar\]/g, "$");
  temp = temp.replace(/\[tilde\]/g, "^");
  temp = temp.replace(/\[at\]/g, "@");
  temp = temp.replace(/\[is\]/g, "=");
  temp = temp.replace(/\[.\]/g, "<span style='color:#d3e8ef'>.</span>");
  temp = temp.replace(/\{/g, "<");
  temp = temp.replace(/\}/g, ">");
  temp = temp.replace(/`/g, "'");

  return temp;
}

