function lightbox(value) {
  if (!lightboxvisible) {
    lightboxvisible = true;
    $("body").append(
      "<div id='lightbox' style='position:absolute; top:0; width:100%; height:100%; background: rgba(0,0,0,0.5)'><div style='display:table;width:100%;height:100%'><div style='display:table-cell; text-align: center; vertical-align:middle; width:100%; height:100%'><div id='lightboxcontent' style='width:640px;display:inline-block; box-shadow: 0px 0px 10px 0px rgba(0, 0, 0, 1); border:2px solid #a2ccdd; background:#d3e8ef; border-radius:20px; padding:40px; padding-top:80px; position: relative;'><div id='closelightbox' class='geleKnop' style='display: block; position:absolute; top:20px; right: 20px;'>x</div></div></div></div></div>"
    );
    $("#lightboxcontent").unbind();
    $("#closelightbox").bind(clickevent, function () {
      lightboxvisible = false;
      $("#lightbox").remove();
    });
    if (value == "voorlezen") {
      $("#lightboxcontent").append(vertaling["fv_uitleg_voorlezen"]);
      $("#lightboxcontent").playsound("voorlezen.mp3");
    }
    if (value == "wachtwoordvergeten") {
      $("#lightboxcontent").append(
        "Voer hier uw e-mailadres in zodat wij u uw wachtwoord opnieuw kunnen toesturen."
      );
    }

    if (value == "vergroten") {
      $("#lightboxcontent").append(vertaling["fv_uitleg_f11"]);
      $("#lightboxcontent").playsound("f11.mp3");
    }

    add = "?rel=0&showinfo=0";
    temp = youtubekey.split("?")[1];
    if (typeof temp != "undefined") {
      add = "&rel=0&showinfo=0";
    }

    if (value == "youtube") {
      $("#lightboxcontent").append(
        '<iframe width="640" height="360" src="https://www.youtube.com/embed/' +
          youtubekey +
          "" +
          add +
          '" frameborder="0" allowfullscreen></iframe>'
      );
      $("#lightboxcontent").playsound("");
    }

    if (value == "vimeo") {
      $("#lightboxcontent").append(
        '<iframe src="//player.vimeo.com/video/' +
          youtubekey +
          '?color=ffffff&title=0&byline=0&portrait=0" width="640" height="360" frameborder="0" webkitallowfullscreen mozallowfullscreen allowfullscreen></iframe>'
      );

      $("#lightboxcontent").playsound("");
    }
  }
}

Array.prototype.shuffle = function () {
  var len = this.length;
  var i = len;
  while (i--) {
    var p = parseInt(Math.random() * len);
    var t = this[i];
    this[i] = this[p];
    this[p] = t;
  }
};

function checkYouTubeLinks() {
  $("#content a").bind(clickevent, function (event) {
    code = event.currentTarget.href;
    code = code.split("https://www.youtube.com/watch?v=")[1];
    if (typeof code != "undefined") {
      youtubekey = code;
      lightbox("youtube");
      event.preventDefault();
    }

    code = event.currentTarget.href;
    code = code.split("http://vimeo.com/")[1];
    if (typeof code != "undefined") {
      youtubekey = code;
      lightbox("vimeo");
      event.preventDefault();
    }

    code = event.currentTarget.href;
    code = code.split("http://youtu.be/")[1];
    if (typeof code != "undefined") {
      youtubekey = code;
      lightbox("youtube");
      event.preventDefault();
    }

    code = event.currentTarget.href;
    code = code.split("https://youtu.be/")[1];
    if (typeof code != "undefined") {
      youtubekey = code;
      lightbox("youtube");
      event.preventDefault();
    }
  });
}

function replaceSelectWithDiv(selectId) {

  const selectEl = document.getElementById(selectId);
  if (!selectEl) return; // Guard if no element

  const dropdownDiv = document.createElement("div");
  dropdownDiv.classList.add("custom-dropdown");

  const selectedValueDiv = document.createElement("div");
  selectedValueDiv.classList.add("selected-value");
  selectedValueDiv.textContent =
    selectEl.options[selectEl.selectedIndex]?.text || "...";
  dropdownDiv.appendChild(selectedValueDiv);

  const dropdownList = document.createElement("div");
  dropdownList.classList.add("dropdown-list");

  Array.from(selectEl.options).forEach((option) => {
    const itemDiv = document.createElement("div");
    itemDiv.classList.add("dropdown-item");
    itemDiv.textContent = option.text;
    itemDiv.dataset.value = option.value;
    dropdownList.appendChild(itemDiv);
    itemDiv.addEventListener("mouseover", () => {
      playAudioFile(option.value);

    });

    itemDiv.addEventListener("click", () => {
      selectedValueDiv.textContent = option.text;

      selectEl.value = option.value;

      $("#zoekoptitel").val("");
      gekozentitel = "";
      gekozentrefwoord = $("#trefwoorden").val();
      if (gekozentrefwoord == "...") {
        gekozentrefwoord = "";
      }

      createFrontTemp("krant-binnenland", "boek-humor");


      dropdownDiv.classList.remove("show");
    });
  });

  dropdownDiv.appendChild(dropdownList);


  selectEl.parentNode.insertBefore(dropdownDiv, selectEl);

  selectEl.style.display = "none";


  selectedValueDiv.addEventListener("click", () => {

    dropdownDiv.classList.toggle("show");
  });

  document.addEventListener("click", (event) => {
    if (!dropdownDiv.contains(event.target)) {
      dropdownDiv.classList.remove("show");
    }
  });
}

document.addEventListener("DOMContentLoaded", () => {
  replaceSelectWithDiv("mySelect");
});

